  mobileAppPage: { metaTitle: 'Mobile App', metaDescription: 'Greifen Sie unterwegs auf Ihre Dienstpläne zu mit der Roaster Mobile App.', tagline: 'Mobile App', title: 'Ihr Dienstplan in der Tasche', subtitle: 'Mitarbeiter können Dienstpläne einsehen, Schichten tauschen und Stunden erfassen — alles vom Smartphone.', downloadAppStore: 'Laden im', appStore: 'App Store', getItOn: 'Jetzt bei', googlePlay: 'Google Play', appPreview: 'App-Vorschau', features: [{ title: 'Dienstplan einsehen', description: 'Sehen Sie Ihre kommenden Schichten auf einen Blick in einer übersichtlichen Kalenderansicht.' }, { title: 'Schichten tauschen', description: 'Beantragen Sie Schichttausch mit Kollegen direkt vom Smartphone.' }, { title: 'Ein-/Ausstempeln', description: 'Erfassen Sie Ihre Arbeitszeiten mit GPS-verifizierter Zeiterfassung.' }, { title: 'Sofortige Benachrichtigungen', description: 'Werden Sie sofort über Dienstplanänderungen informiert.' }, { title: 'Urlaub beantragen', description: 'Reichen Sie Urlaubs- und Freistellungsanträge mit einem Tipp ein.' }, { title: 'Team-Chat', description: 'Kommunizieren Sie direkt in der App mit Ihrem Team.' }], everythingTitle: 'Alles was Ihre Mitarbeiter brauchen', everythingSubtitle: 'Leistungsstarke Funktionen in einer einfachen, intuitiven App', appStoreRating: 'App Store Bewertung', activeUsers: 'Aktive Nutzer', userSatisfaction: 'Nutzerzufriedenheit', avgCheckTime: 'Durchschn. Prüfzeit', ctaTitle: 'Bereit loszulegen?', ctaText: 'Starten Sie Ihre kostenlose Testversion und geben Sie Ihren Mitarbeitern Zugang zur Mobile App.' },
  complianceGuidePage: { metaTitle: 'Compliance-Leitfaden', metaDescription: 'Vollständiger Leitfaden zur AZG-Compliance bei der Dienstplanung.', tagline: 'Ressourcen', title: 'Compliance-Leitfaden', subtitle: 'Alles, was Sie über die AZG-Anforderungen an die Dienstplanung wissen müssen.', aboutTitle: 'Über das Arbeitszeitgesetz (AZG)', aboutText: 'Das Arbeitszeitgesetz (AZG) legt umfassende Anforderungen an Arbeitszeiten, Ruhezeiten und die Veröffentlichung von Dienstplänen fest. Diese Vorschriften werden vom Arbeitsinspektorat durchgesetzt.', sections: [{ law: '§ 10-3', title: '14-Tage-Veröffentlichungsregel', description: 'Dienstpläne müssen mindestens 14 Tage vor Inkrafttreten veröffentlicht werden. Mitarbeiter haben das Recht, ihren Arbeitsplan im Voraus zu kennen.', tips: ['Automatische Erinnerungen für Veröffentlichungsfristen einrichten', 'Entwurfs-Dienstpläne zur Vorausplanung nutzen', 'Ausnahmen mit Mitarbeitervereinbarungen dokumentieren'] }, { law: '§ 10-8', title: 'Tägliche Ruhezeiten', description: 'Mitarbeiter müssen mindestens 11 Stunden ununterbrochene Ruhezeit zwischen Arbeitsperioden haben.', tips: ['Automatische Validierung verhindert Planungsverstöße', 'Ausgleichsruhe-Anforderungen nachverfolgen', 'Vereinbarte Ausnahmen dokumentieren'] }, { law: '§ 10-8', title: 'Wöchentliche Ruhezeiten', description: 'Mitarbeiter müssen mindestens 36 Stunden ununterbrochene Ruhezeit pro Woche haben, möglichst einschließlich Sonntag.', tips: ['Wöchentliche Ruhezeit mit Nachtstunden planen', 'Sonntagsarbeit nur bei Bedarf einplanen', '36-Stunden-Minimum einhalten'] }, { law: '§ 10-4', title: 'Maximale Arbeitszeiten', description: 'Die reguläre Arbeitszeit darf 9 Stunden pro Tag und 40 Stunden pro Woche nicht überschreiten.', tips: ['Kumulative Stunden über alle Schichten verfolgen', 'Annäherung an Grenzwerte überwachen', 'Abdeckung für Spitzenzeiten planen'] }, { law: '§ 10-6', title: 'Überstundengrenzen', description: 'Überstunden sind auf 10 Stunden pro Woche, 25 Stunden pro 4 Wochen und 200 Stunden pro Jahr begrenzt.', tips: ['Echtzeit-Überstundenverfolgung', 'Automatische Warnungen vor Erreichen der Grenzen', 'Überstundennotwendigkeit dokumentieren'] }, { law: '§ 10-7', title: 'Aufzeichnungspflicht', description: 'Arbeitgeber müssen Aufzeichnungen über die Arbeitszeiten jedes Mitarbeiters führen. Diese Aufzeichnungen müssen 2 Jahre aufbewahrt werden.', tips: ['Automatische Stundenerfassung und -speicherung', 'Einfacher Export für Inspektionen', 'Vollständiger Audit-Trail'] }], howWeHelp: 'Wie Roaster hilft:', needHelp: 'Brauchen Sie Hilfe bei der Compliance?', needHelpText: 'Roaster automatisiert die Compliance-Validierung, damit Sie sich auf Ihr Geschäft konzentrieren können.', talkToExpert: 'Mit einem Experten sprechen' },
  apiDocsPage: { metaTitle: 'API-Dokumentation', metaDescription: 'Entwickler-Dokumentation für die Roaster REST API.', tagline: 'Entwickler', title: 'API-Dokumentation', subtitle: 'Erstellen Sie individuelle Integrationen mit der Roaster REST API.', quickStart: 'Schnellstart', authentication: 'Authentifizierung', authText: 'Alle API-Anfragen erfordern eine Authentifizierung mit einem API-Schlüssel. Fügen Sie Ihren Schlüssel in den Authorization-Header ein:', baseUrl: 'Basis-URL', exampleRequest: 'Beispielanfrage', endpoints: 'Endpunkte', apiEndpoints: [{ method: 'GET', endpoint: '/employees', description: 'Alle Mitarbeiter auflisten' }, { method: 'POST', endpoint: '/employees', description: 'Neuen Mitarbeiter erstellen' }, { method: 'GET', endpoint: '/rosters', description: 'Alle Dienstpläne auflisten' }, { method: 'POST', endpoint: '/rosters', description: 'Neuen Dienstplan erstellen' }, { method: 'GET', endpoint: '/shifts', description: 'Schichten mit Filtern auflisten' }, { method: 'POST', endpoint: '/shifts', description: 'Neue Schicht erstellen' }, { method: 'POST', endpoint: '/compliance/validate', description: 'Dienstplan-Compliance validieren' }, { method: 'GET', endpoint: '/reports/hours', description: 'Arbeitszeitbericht abrufen' }], rateLimits: 'Rate-Limits', requestsPerMinute: 'Anfragen pro Minute', basedOnNeeds: 'basierend auf Ihren Bedürfnissen', sdks: 'SDKs & Bibliotheken', readyToIntegrate: 'Bereit zur Integration?', apiAccessInfo: 'API-Zugang ist in den Professional- und Enterprise-Plänen verfügbar.' },
